import{_ as a,o as r,c as t,ah as i}from"./chunks/framework.D-EW4Mou.js";const I=JSON.parse('{"title":"网络编程","description":"","frontmatter":{"title":"网络编程","order":10},"headers":[],"relativePath":"server/network/index.md","filePath":"server/network/index.md"}'),l={name:"server/network/index.md"};function p(o,e,n,c,h,s){return r(),t("div",null,[...e[0]||(e[0]=[i('<h1 id="网络编程" tabindex="-1">网络编程 <a class="header-anchor" href="#网络编程" aria-label="Permalink to “网络编程”">​</a></h1><p>服务端开发的本质是处理网络 I/O：接收客户端请求、解析协议、处理业务、返回响应。理解网络编程的底层原理，是构建高性能服务的基础。</p><h2 id="网络分层模型" tabindex="-1">网络分层模型 <a class="header-anchor" href="#网络分层模型" aria-label="Permalink to “网络分层模型”">​</a></h2><p>TCP/IP 模型是互联网的实际标准，将 OSI 七层合并为四层。</p><ul><li>应用层：对应 OSI 的应用层、表示层、会话层，如 HTTP、DNS、SSH。</li><li>传输层：端到端通信，如 TCP、UDP。</li><li>网络层：路由转发，如 IP、ICMP。</li><li>网络接口层：对应 OSI 的数据链路层、物理层，如 Ethernet、Wi-Fi。</li></ul><h2 id="socket-编程基础" tabindex="-1">Socket 编程基础 <a class="header-anchor" href="#socket-编程基础" aria-label="Permalink to “Socket 编程基础”">​</a></h2><p>Socket 是网络编程的抽象，屏蔽了底层协议细节。一个 Socket 连接由五元组标识：源 IP、源端口、目的 IP、目的端口、协议。</p><h3 id="socket-类型" tabindex="-1">Socket 类型 <a class="header-anchor" href="#socket-类型" aria-label="Permalink to “Socket 类型”">​</a></h3><p>流式套接字（SOCK_STREAM）基于 TCP，提供可靠、面向连接的字节流服务。</p><p>数据报套接字（SOCK_DGRAM）基于 UDP，提供不可靠、无连接的数据报服务。</p><p>原始套接字（SOCK_RAW）绕过传输层，直接操作 IP 层，需要 root 权限。</p><h3 id="tcp-连接建立" tabindex="-1">TCP 连接建立 <a class="header-anchor" href="#tcp-连接建立" aria-label="Permalink to “TCP 连接建立”">​</a></h3><p>三次握手：客户端发送 SYN，服务端回复 SYN+ACK，客户端回复 ACK。</p><p>ISN（Initial Sequence Number）是初始序列号，随机生成，防止序列号猜测攻击。</p><h3 id="tcp-连接终止" tabindex="-1">TCP 连接终止 <a class="header-anchor" href="#tcp-连接终止" aria-label="Permalink to “TCP 连接终止”">​</a></h3><p>四次挥手：主动方发送 FIN，被动方回复 ACK，被动方发送 FIN，主动方回复 ACK。</p><p>TIME_WAIT 状态持续 2MSL（Maximum Segment Lifetime，约 60 秒），确保最后的 ACK 能够到达，确保旧连接的报文段在网络中消失。</p><h2 id="i-o-模型" tabindex="-1">I/O 模型 <a class="header-anchor" href="#i-o-模型" aria-label="Permalink to “I/O 模型”">​</a></h2><p>阻塞 I/O：进程阻塞直到数据准备好并拷贝到用户空间。简单直观，但一个线程只能处理一个连接。</p><p>非阻塞 I/O：进程立即返回，不管数据是否准备好。进程需要不断轮询，浪费 CPU。</p><p>I/O 多路复用：select/poll/epoll 同时监控多个文件描述符，任一描述符就绪时返回。一个线程处理多个连接。</p><p>信号驱动 I/O：内核就绪时发送 SIGIO 信号，进程在信号处理函数中处理 I/O。</p><p>异步 I/O：进程发起 I/O 后立即返回，I/O 完成后内核通知进程。真正的异步，但支持有限。</p><h2 id="网络性能优化" tabindex="-1">网络性能优化 <a class="header-anchor" href="#网络性能优化" aria-label="Permalink to “网络性能优化”">​</a></h2><p>零拷贝：减少数据拷贝次数和上下文切换，提升 I/O 性能。</p><p>I/O 多路复用：使用 epoll 等机制，单线程处理大量连接。</p><p>TCP 参数调优：调整缓冲区大小、超时时间、拥塞控制参数。</p><p>连接池：复用连接，减少连接建立和关闭的开销。</p><p>网络编程是服务端开发的基础，理解网络协议、I/O 模型、性能优化，有助于构建高性能的服务端程序。</p>',29)])])}const P=a(l,[["render",p]]);export{I as __pageData,P as default};
